  // Test Kullanicisi
  const hashedPw = await bcrypt.hash("test1234", 10);
  const testUser = await prisma.user.upsert({
    where: { email: "test@deutschmeister.com" },
    update: {},
    create: {
      email: "test@deutschmeister.com",
      name: "Ahmet Yilmaz",
      password: hashedPw,
      currentLevel: "A1",
      streak: 7,
      totalXP: 4250,
      role: "student",
    },
  });

  // Beceri puanlari
  const skills = [
    { skill: "horen", score: 68 },
    { skill: "lesen", score: 75 },
    { skill: "schreiben", score: 55 },
    { skill: "sprechen", score: 48 },
    { skill: "grammatik", score: 72 },
  ];
  for (const s of skills) {
    await prisma.userProgress.upsert({
      where: { userId_skill: { userId: testUser.id, skill: s.skill } },
      update: { score: s.score },
      create: { userId: testUser.id, skill: s.skill, score: s.score },
    });
  }

  // Haftalik calisma (son 7 gun)
  const today = new Date();
  const weekMinutes = [45, 60, 30, 90, 75, 60, 45];
  for (let i = 0; i < 7; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - (6 - i));
    d.setHours(12, 0, 0, 0);
    await prisma.userWorkSession.create({
      data: { userId: testUser.id, date: d, minutesWorked: weekMinutes[i] },
    });
  }

  // Ogrenilmis kelimeler (ilk 15)
  const vocabs = await prisma.vocabulary.findMany({ take: 15, where: { levelId: a1.id } });
  for (const v of vocabs) {
    await prisma.userVocabulary.upsert({
      where: { userId_vocabularyId: { userId: testUser.id, vocabularyId: v.id } },
      update: {},
      create: {
        userId: testUser.id,
        vocabularyId: v.id,
        confidenceLevel: 2.5,
        interval: 3,
        repetitions: 2,
        nextReviewDate: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000),
      },
    });
  }

